column.value:
{
  "pageDescription": "Sample Reception & Registration",
  "dataPoints": {
    "sampleIdentity": {
      "sampleId": {"type": "text", "label": "Sample ID", "required": true},
      "sampleType": {"type": "choice", "label": "Sample Type", "options": ["API", "Tablet", "Plasma", "Serum", "Urine", "Other biological matrix"], "required": true},
      "sourceOrigin": {"type": "choice", "label": "Source Origin", "options": ["Medical Laboratory", "External Client", "Contract Research Organization"], "required": true}
    },
    "testRequirements": {
      "requestedTests": {"type": "multiSelect", "label": "Requested Tests", "options": ["Bioequivalence Study", "Dissolution", "Content Uniformity", "Assay", "Impurities", "Pharmacokinetic Analysis"], "required": true},
      "studyProtocol": {"type": "text", "label": "Study Protocol", "required": false}
    },
    "receptionMetadata": {
      "dateTimeOfReceipt": {"type": "dateTime", "label": "Date/Time of Receipt", "required": true},
      "receivingPersonnel": {"type": "text", "label": "Receiving Personnel", "required": true},
      "storageConditionOnArrival": {"type": "choice", "label": "Storage Condition on Arrival", "options": ["Room Temperature", "Refrigerated (2-8°C)", "Frozen (-20°C)", "Ultra-frozen (-80°C)"], "required": true}
    },
    "studyLinking": {
      "bioequivalenceStudy": {"type": "reference", "label": "Bioequivalence Study", "source": "bioequivalence_study", "required": false},
      "subjectId": {"type": "text", "label": "Subject ID", "required": false},
      "timepoint": {"type": "text", "label": "Sampling Timepoint", "required": false}
    }
  },
  "systemActions": ["Generate unique system ID", "Assign barcode label", "Set status: Registered - Awaiting Processing"],
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["dateTimeOfReceipt", "receivingPersonnel", "storageConditionOnArrival"]
  },
  "manifestImport": {
    "csvColumnMapping": {
      "sampleIdColumn": "Sample ID",
      "sampleTypeColumn": "Sample Type",
      "sourceOriginColumn": "Source Origin",
      "requestedTestsColumn": "Requested Tests",
      "dateTimeOfReceiptColumn": "Date/Time of Receipt",
      "receivingPersonnelColumn": "Receiving Personnel"
    }
  },
  "nextPage": "Test Assignment & Preparation"
}

{
  "pageDescription": "Test Assignment & Preparation",
  "dataPoints": {
    "testAssignment": {
      "assignedAnalyst": {"type": "reference", "label": "Assigned Analyst/Pharmacist", "source": "system_user", "required": true},
      "testCategory": {"type": "choice", "label": "Test Category", "options": ["Bioanalytical", "Dissolution", "Content Uniformity", "Assay", "Impurities"], "required": true},
      "expectedAnalysisDate": {"type": "date", "label": "Expected Analysis Date", "required": true}
    },
    "analyticalMethodology": {
      "analyticalMethod": {"type": "choice", "label": "Analytical Method", "options": ["HPLC UV-Vis", "LC-MS/MS", "GC-MS", "Dissolution Apparatus", "Spectrophotometry"], "required": true},
      "instrumentId": {"type": "reference", "label": "Instrument ID", "source": "instrument_inventory", "required": true},
      "calibrationStatus": {"type": "choice", "label": "Calibration Status", "options": ["Current", "Expired", "Pending"], "required": true}
    },
    "samplePreparation": {
      "preparationMethodology": {"type": "text", "label": "Sample Preparation Methodology", "required": true},
      "extractionMethod": {"type": "choice", "label": "Extraction Method", "options": ["Protein Precipitation", "Liquid-Liquid Extraction", "Solid Phase Extraction", "Direct Injection"], "required": false}
    },
    "qcRequirements": {
      "calibrationCurveCriteria": {"type": "text", "label": "Calibration Curve Criteria (r² ≥ 0.99)", "required": true},
      "controlSamples": {"type": "choice", "label": "Control Samples", "options": ["Low, Medium, High QC", "LLOQ, Mid, ULOQ"], "required": true},
      "acceptanceCriteria": {"type": "text", "label": "Acceptance Criteria (±15%, ±20% at LLOQ)", "required": true}
    }
  },
  "systemActions": ["Assign analyst to samples", "Link analytical method to test", "Update status: Test Assigned"],
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["assignedAnalyst", "testCategory", "analyticalMethod", "instrumentId"]
  },
  "nextPage": "Analytical Test Execution"
}

{
  "pageDescription": "Analytical Test Execution",
  "dataPoints": {
    "executionMetadata": {
      "executionDateTime": {"type": "dateTime", "label": "Execution Date/Time", "required": true},
      "analystId": {"type": "reference", "label": "Analyst ID", "source": "system_user", "required": true},
      "runSequence": {"type": "integer", "label": "Run Sequence Number", "required": true}
    },
    "calibrationCurve": {
      "rSquaredValue": {"type": "number", "label": "r² Value", "min": 0.99, "required": true},
      "slope": {"type": "number", "label": "Slope", "required": true},
      "intercept": {"type": "number", "label": "Intercept", "required": true},
      "acceptanceCriteria": {"type": "choice", "label": "Acceptance Criteria Met", "options": ["Yes", "No"], "required": true}
    },
    "qcSamples": {
      "lowQcResult": {"type": "number", "label": "Low QC Result", "required": true},
      "mediumQcResult": {"type": "number", "label": "Medium QC Result", "required": true},
      "highQcResult": {"type": "number", "label": "High QC Result", "required": true},
      "qcAcceptanceLimits": {"type": "text", "label": "QC Acceptance Limits (±15%, ±20% at LLOQ)", "required": true}
    },
    "rawDataCapture": {
      "chromatogramFiles": {"type": "fileUpload", "label": "Chromatograms/Spectra Files", "acceptedFormats": [".pdf", ".raw", ".wiff", ".d"], "required": true},
      "calculatedResults": {"type": "number", "label": "Calculated Results", "unit": "ng/mL or μg/mL", "required": true},
      "resultsUnit": {"type": "choice", "label": "Results Unit", "options": ["ng/mL", "μg/mL", "mg/L", "%"], "required": true}
    },
    "qualityControl": {
      "deviations": {"type": "text", "label": "Deviations (if any)", "required": false},
      "alcoaCompliance": {"type": "boolean", "label": "ALCOA+ Compliance Verified", "description": "Attributable, Legible, Contemporaneous, Original, Accurate, Complete", "required": true}
    }
  },
  "systemActions": ["Store raw data files", "Calculate final results", "Update status: Analysis Complete", "Generate data integrity audit trail"],
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["executionDateTime", "analystId", "qcAcceptanceLimits"]
  },
  "nextPage": "Reporting & Release"
}

{
  "pageDescription": "Reporting & Release",
  "dataPoints": {
    "resultCompilation": {
      "sampleResults": {"type": "aggregated", "label": "Compiled Sample Results", "source": "analytical_execution", "required": true},
      "acceptanceCriteriaValidation": {"type": "choice", "label": "Results Meet Acceptance Criteria", "options": ["Yes", "No", "Conditional"], "required": true}
    },
    "reviewProcess": {
      "primaryReview": {
        "analystValidation": {"type": "boolean", "label": "Primary Review (Analyst Validation)", "required": true},
        "primaryReviewer": {"type": "reference", "label": "Primary Reviewer", "source": "system_user", "required": true},
        "primaryReviewDate": {"type": "date", "label": "Primary Review Date", "required": true}
      },
      "secondaryReview": {
        "seniorScientistReview": {"type": "boolean", "label": "Secondary Review (Senior Scientist/QA)", "required": true},
        "secondaryReviewer": {"type": "reference", "label": "Secondary Reviewer", "source": "system_user", "required": true},
        "secondaryReviewDate": {"type": "date", "label": "Secondary Review Date", "required": true}
      },
      "finalApproval": {
        "labManagerApproval": {"type": "boolean", "label": "Final Approval (Lab Manager/Study Director)", "required": true},
        "finalApprover": {"type": "reference", "label": "Final Approver", "source": "system_user", "required": true},
        "finalApprovalDate": {"type": "date", "label": "Final Approval Date", "required": true}
      }
    },
    "resultDistribution": {
      "distributionMethod": {"type": "choice", "label": "Result Distribution Method", "options": ["Email", "REDCap Integration", "LIMS Integration", "Manual Delivery"], "required": true},
      "recipientList": {"type": "multiSelect", "label": "Recipients", "source": "contact_list", "required": true}
    },
    "performanceMetrics": {
      "dashboardGeneration": {"type": "boolean", "label": "Generate Performance Metrics Dashboard", "required": true},
      "dataIntegrityDocumentation": {"type": "boolean", "label": "Document Data Integrity", "required": true},
      "auditTrailComplete": {"type": "boolean", "label": "Audit Trail Complete", "required": true}
    }
  },
  "systemActions": ["Generate analytical report", "Create performance dashboard", "Archive audit trail", "Update status: Report Released", "Notify stakeholders"],
  "reportGeneration": {
    "templates": ["Bioequivalence Study Report", "Analytical Certificate", "QC Summary Report"],
    "embedDashboard": true
  },
  "nextPage": "Post-Test Storage & Archiving"
}

{
  "pageDescription": "Post-Test Storage & Archiving",
  "dataPoints": {
    "sampleRetention": {
      "quantityRetained": {"type": "number", "label": "Quantity Retained for Storage", "unit": "mL or tubes", "required": true},
      "transferToBiorepository": {"type": "choice", "label": "Transfer to Biorepository", "options": ["Yes - Long-term storage", "No - Local storage", "Partial transfer"], "required": true},
      "storageTemperature": {"type": "choice", "label": "Storage Temperature", "options": ["-80°C (biological samples)", "-20°C", "2-8°C", "Room temperature (pharmaceutical)"], "required": true}
    },
    "storageLocationHierarchy": {
      "room": {"type": "reference", "label": "Room", "source": "storage_room", "required": true},
      "freezer": {"type": "reference", "label": "Freezer", "source": "storage_device", "required": true},
      "shelf": {"type": "reference", "label": "Shelf", "source": "storage_shelf", "required": true},
      "rack": {"type": "reference", "label": "Rack", "source": "storage_rack", "required": true},
      "box": {"type": "reference", "label": "Box", "source": "storage_box", "required": true},
      "position": {"type": "text", "label": "Position", "required": true}
    },
    "retentionPolicy": {
      "retentionPeriod": {"type": "choice", "label": "Retention Period", "options": ["2 years (bioequivalence)", "5-10 years (regulatory)", "Custom period"], "required": true},
      "customRetentionPeriod": {"type": "text", "label": "Custom Retention Period", "conditionalOn": "retentionPeriod == Custom period", "required": false},
      "regulatoryRequirement": {"type": "choice", "label": "Regulatory Requirement", "options": ["FDA", "EMA", "ICH", "Local Authority"], "required": false}
    },
    "environmentalMonitoring": {
      "temperatureMonitoring": {"type": "boolean", "label": "Temperature Monitoring Setup", "required": true},
      "alarmSystem": {"type": "boolean", "label": "Alarm System Active", "required": true},
      "monitoringFrequency": {"type": "choice", "label": "Monitoring Frequency", "options": ["Continuous", "Daily", "Weekly"], "required": true}
    },
    "dataArchiving": {
      "rawDataLocation": {"type": "text", "label": "Raw Data Archiving Location", "required": true},
      "backupLocation": {"type": "text", "label": "Backup Location", "required": true},
      "archiveFormat": {"type": "choice", "label": "Archive Format", "options": ["Digital (PDF/A)", "Physical printouts", "Both digital and physical"], "required": true}
    },
    "disposalCriteria": {
      "disposalCriteria": {"type": "text", "label": "Disposal Criteria", "required": true},
      "disposalMethod": {"type": "choice", "label": "Disposal Method", "options": ["Autoclave", "Incineration", "Chemical treatment", "Standard waste"], "required": true},
      "traceabilityMaintenance": {"type": "boolean", "label": "Sample-Result Traceability Maintained", "required": true}
    }
  },
  "systemActions": ["Update storage location", "Set retention period", "Initialize environmental monitoring", "Archive analytical data", "Update status: Archived"],
  "bulkOperations": {
    "enabled": true,
    "applyToSelected": ["storageTemperature", "room", "freezer", "retentionPeriod"]
  },
  "complianceChecks": ["Temperature range validation", "Access control verification", "Inventory tracking setup", "Environmental monitoring active", "Data archiving complete"],
  "nextPage": null
}
